export type AreaRentStat = { avg: number; median: number; n: number };
export type AreaRentStats = Partial<Record<BHKConfig, AreaRentStat>>;

export const RENT_BHK_OPTIONS: BHKConfig[] = ["1 BHK", "2 BHK", "3 BHK"];

function median(nums: number[]): number {
  const s = [...nums].sort((a, b) => a - b);
  return s[Math.floor(s.length / 2)];
}

// Crowdsourced listings skew low (placeholder/lowball entries are common,
// especially for PG/1RK). Every figure surfaced in the UI gets scaled up to
// correct for that — proportional for cheap units, capped for expensive ones,
// so a ₹13k room doesn't get the same absolute bump as a ₹1L apartment.
function adjustRent(rent: number): number {
  return rent + Math.min(rent * 0.4, 10000);
}

const statsCache = new Map<string, AreaRentStats>();

export function areaRentStats(area: string): AreaRentStats {
  if (statsCache.has(area)) return statsCache.get(area)!;
  const byConfig = new Map<BHKConfig, number[]>();
  for (const p of RENT_PINS) {
    if (p.area !== area) continue;
    (byConfig.get(p.config) ?? byConfig.set(p.config, []).get(p.config)!).push(p.rent);
  }
  const out: AreaRentStats = {};
  for (const [config, rents] of byConfig) {
    out[config] = {
      avg: Math.round(adjustRent(rents.reduce((a, b) => a + b, 0) / rents.length)),
      median: Math.round(adjustRent(median(rents))),
      n: rents.length,
    };
  }
  statsCache.set(area, out);
  return out;
}

export function areaHasRentData(area: string): boolean {
  return RENT_PINS.some((p) => p.area === area);
}

// Shared by the sidebar's area-list filter and the map's area-highlight layer.
export function areaMatchesRentFilter(area: string, budget: string, bhk: BHKConfig | null): boolean {
  const parsedBudget = Number(budget);
  const hasBudget = budget.trim() !== "" && !Number.isNaN(parsedBudget) && parsedBudget > 0;
  if (!hasBudget && !bhk) return true;
  const stats = areaRentStats(area);
  const configs = bhk ? [bhk] : RENT_BHK_OPTIONS;
  return configs.some((c) => {
    const s = stats[c];
    if (!s) return false;
    return hasBudget ? s.median <= parsedBudget : true;
  });
}

export function areaSamplePins(area: string, config?: BHKConfig, limit = 3): RentPin[] {
  return RENT_PINS.filter((p) => p.area === area && (!config || p.config === config)).slice(0, limit);
}

const blendedCache = new Map<string, number | null>();

// Median rent across ALL configs in an area, including PG/1RK — these skew
// the blend low, so this is only used as a last-resort fallback now.
export function areaBlendedMedian(area: string): number | null {
  if (blendedCache.has(area)) return blendedCache.get(area)!;
  const rents = RENT_PINS.filter((p) => p.area === area).map((p) => p.rent);
  const result = rents.length > 0 ? Math.round(adjustRent(median(rents))) : null;
  blendedCache.set(area, result);
  return result;
}

// "Typical" rent for a locality when no specific BHK is picked: family-sized
// units (3 BHK, then 4 BHK) are a far better proxy for an area's going rate
// than blending in cheap PG/1RK rows, which was pulling everything toward
// green regardless of how expensive the area actually is.
export function areaReferenceMedian(area: string): number | null {
  const stats = areaRentStats(area);
  return stats["3 BHK"]?.median ?? stats["4 BHK"]?.median ?? areaBlendedMedian(area);
}

// Resolves the rent figure to color/rank a locality by: the filtered BHK's
// median if available, else the 3BHK/4BHK-anchored reference, else null.
export function areaRentForMode(area: string, config: BHKConfig | null): number | null {
  if (config) {
    const stats = areaRentStats(area);
    const s = stats[config];
    if (s) return s.median;
  }
  return areaReferenceMedian(area);
}

// Green (cheap) → yellow (₹40k, the middle) → red (expensive). Bounds are
// wide enough to spread the "Any config" blended medians (~13k-140k) across
// the full ramp without everything past ~60k clipping to solid red.
const RENT_GREEN = 20000;
const RENT_YELLOW = 40000;
const RENT_RED = 80000;

export function rentColor(rent: number): [number, number, number] {
  const GREEN: [number, number, number] = [34, 197, 94];
  const YELLOW: [number, number, number] = [250, 204, 21];
  const RED: [number, number, number] = [220, 38, 38];
  if (rent <= RENT_GREEN) return GREEN;
  if (rent <= RENT_YELLOW) {
    const f = (rent - RENT_GREEN) / (RENT_YELLOW - RENT_GREEN);
    return [
      Math.round(GREEN[0] + f * (YELLOW[0] - GREEN[0])),
      Math.round(GREEN[1] + f * (YELLOW[1] - GREEN[1])),
      Math.round(GREEN[2] + f * (YELLOW[2] - GREEN[2])),
    ];
  }
  if (rent >= RENT_RED) return RED;
  const f = (rent - RENT_YELLOW) / (RENT_RED - RENT_YELLOW);
  return [
    Math.round(YELLOW[0] + f * (RED[0] - YELLOW[0])),
    Math.round(YELLOW[1] + f * (RED[1] - YELLOW[1])),
    Math.round(YELLOW[2] + f * (RED[2] - YELLOW[2])),
  ];
}
